def score_of_parentheses(s):
    """
    Verilen dengeli bir parantez dizesinin skorunu hesaplar.

    Parametreler:
    s (str): Dengeli bir parantez dizesi.

    Döndürür:
    int: Dizenin skoru.
    """
    stack = [0]  # Skorları depolamak için yığın

    for char in s:
        if char == '(':
            stack.append(0)  # Yeni bir alt ifade başlat
        else:
            # Yığılmış alt ifadenin skorunu hesaplayın
            top = stack.pop()
            if top == 0:
                stack[-1] += 1  # "()" için skor 1'dir
            else:
                stack[-1] += 2 * top  # "(A)" için skor 2 * A'dır

    return stack[0]
